{% extends "base.html" %}
{% block title %}Members{% endblock %}
{% block content %}
  <ul>
  {% for user in users if not user.hidden recursive %}
    <li><a href="{{ user.url }}">{{ user.username|e }}</a></li>
    {{ loop(user.children) }}
  {% else %}
    <li>no users</li>
  {% endfor %}
  </ul>
{% endblock %}
